/**
 * Regression lock for {@link ../formal-ledger.ts} — families and primitives are the
 * reducer contract consumed downstream (`FormalLedgerBundle`, aeon-shell digest). Any
 * intentional change must update this snapshot and downstream consumers.
 */
import {
  FORMAL_LEDGER_FAMILIES,
  FORMAL_LEDGER_PRIMITIVES,
} from '../formal-ledger';

/** Lexicographic snapshot — add/remove/rename is always an explicit edit here. */
const EXPECTED_FAMILIES_SORTED = [
  'community',
  'metacognition',
  'negotiation',
  'probability',
  'recovery',
  'voidWalking',
] as const;

const EXPECTED_PRIMITIVES_SORTED = [
  'fold',
  'fork',
  'interfere',
  'race',
  'vent',
] as const;

function assertSameSorted<T extends string>(
  label: string,
  actual: readonly T[],
  expectedSorted: readonly T[]
): void {
  if (new Set(actual).size !== actual.length) {
    throw new Error(`${label}: duplicate entries`);
  }
  const a = [...actual].sort();
  const e = [...expectedSorted];
  if (a.length !== e.length || a.some((x, i) => x !== e[i])) {
    throw new Error(
      `${label} set drift.\n  expected (sorted): ${e.join(',')}\n  actual (sorted):   ${a.join(',')}`
    );
  }
}

assertSameSorted('FORMAL_LEDGER_FAMILIES', FORMAL_LEDGER_FAMILIES, [
  ...EXPECTED_FAMILIES_SORTED,
]);
assertSameSorted(
  'FORMAL_LEDGER_PRIMITIVES',
  FORMAL_LEDGER_PRIMITIVES,
  [...EXPECTED_PRIMITIVES_SORTED]
);
